patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -8,7 +8,7 @@ module mux_4to1(
   output reg [7:0] out
 );

-  always @(sel)
+  always @(sel or in0 or in1 or in2 or in3)
     case(sel)
       2'b00: out = in0;
       2'b01: out = in1;

before_code:
module mux_4to1(
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel)
    case(sel)
      2'b00: out = in0;
      2'b01: out = in1;
      2'b10: out = in2;
      2'b11: out = in3;
      default: out = 8'h00;
    endcase

endmodule

after_code:
module mux_4to1(
  input [7:0] in0, in1, in2, in3,
  input [1:0] sel,
  output reg [7:0] out
);

  always @(sel or in0 or in1 or in2 or in3)
    case(sel)
      2'b00: out = in0;
      2'b01: out = in1;
      2'b10: out = in2;
      2'b11: out = in3;
      default: out = 8'h00;
    endcase

endmodule
